local function GetDamageBonusData(owner) local charBonus = 0x0 local charBonusPercentage = 0x0 if owner and owner.GetCharacterBonus then local phase = GetClock().phase local health = owner.components.health local health_p = health and health:GetPercent() local sanity = owner.components.sanity local sanity_p = sanity and sanity:GetPercent() local hunger = owner.components.hunger local hunger_p = hunger and hunger:GetPercent() charBonus = owner:GetCharacterBonus( "damage" ) charBonus = phase and phase == "dusk" and charBonus + owner:GetCharacterBonus( "duskdamage" ) or charBonus charBonus = phase and phase == "night" and charBonus + owner:GetCharacterBonus( "nightdamage" ) or charBonus charBonusPercentage = owner:GetCharacterBonus( "damage_percent" ) charBonusPercentage = health_p and charBonusPercentage + owner:GetCharacterBonus( "woundeddamage_percent" ) * (0x1 - health_p) or charBonusPercentage charBonusPercentage = sanity_p and charBonusPercentage + owner:GetCharacterBonus( "insanedamage_percent" ) * (0x1 - sanity_p) or charBonusPercentage charBonusPercentage = hunger_p and charBonusPercentage + owner:GetCharacterBonus( "hungrydamage_percent" ) * (0x1 - hunger_p) or charBonusPercentage local inv = owner.components.inventory local handheldItem = inv and inv.equipslots[EQUIPSLOTS.HANDS] if not owner.components.combat:GetWeapon() and not handheldItem then charBonus = charBonus + owner:GetCharacterBonus( "fistdamage" ) charBonusPercentage = charBonusPercentage + owner:GetCharacterBonus( "fistdamage_percent" ) end local leader = owner.components.follower and owner.components.follower.leader if leader and type(leader) == "table" and leader.GetCharacterBonus then charBonus = charBonus + leader:GetCharacterBonus( "followerdamage" ) charBonusPercentage = charBonusPercentage + leader:GetCharacterBonus( "followerdamage_percent" ) end end return charBonus, charBonusPercentage end local function GetReductionBonusData(owner) local charBonus = 0x0 local charBonusPercentage = 0x0 if owner and owner.GetCharacterBonus then charBonus = owner:GetCharacterBonus( "damagereduction" ) charBonusPercentage = owner:GetCharacterBonus( "damagereduction_percent" ) local leader = owner.components.follower and owner.components.follower.leader if leader and type(leader) == "table" and leader.GetCharacterBonus then charBonus = charBonus + leader:GetCharacterBonus( "followerdamagereduction" ) charBonusPercentage = charBonusPercentage + leader:GetCharacterBonus( "followerdamagereduction_percent" ) end end return charBonus, charBonusPercentage end local function CalcEstimatedDamage(self, weapon) local multiplier = 0x1 multiplier = multiplier * (self.GetDamageModifier and self:GetDamageModifier() or self.damagemultiplier or 0x1) local basedamage = self.defaultdamage or 0x0 local bonus = self.damagebonus or 0x0 if weapon and weapon.components.weapon then local weapondamage = 0x0 if weapon.components.weapon.variedmodefn then local d = weapon.components.weapon.variedmodefn(weapon) weapondamage = d.damage else weapondamage = weapon.components.weapon:GetDamage() end if not weapondamage then weapondamage = 0x0 end return weapondamage * multiplier + bonus else if self.inst.components.rider and self.inst.components.rider:IsRiding() then local mount = self.inst.components.rider:GetMount() if mount and mount.components.combat then basedamage = mount.components.combat.defaultdamage bonus = mount.components.combat.damagebonus or 0x0 end local saddle = self.inst.components.rider:GetSaddle() if saddle ~= nil and saddle.components.saddler ~= nil then basedamage = basedamage + saddle.components.saddler:GetBonusDamage() end end end local charBonus, charBonusPercentage = GetDamageBonusData(self.inst) local damage_base = basedamage * multiplier + bonus local damage = math.max(damage_base + charBonus * multiplier, 0x0) * (0x1 + charBonusPercentage) local damage_bonus = damage - damage_base return damage, damage_base, damage_bonus end local function CalcDamage(self, target, weapon, multiplier, ...) local weaponComp = weapon and weapon.components.weapon local charBonus = 0x0 local charBonusPercentage = 0x0 if not weaponComp then local owner = self.inst charBonus, charBonusPercentage = GetDamageBonusData(owner) end local damageOriginal = 0x0 if weaponComp and not weaponComp.dycShouldOverrideCalcDamage then damageOriginal = self.dycOldCalcDamage(self, target or self.inst, weapon, multiplier, ...) charBonus = 0x0 charBonusPercentage = 0x0 elseif not weaponComp then damageOriginal = self.dycOldCalcDamage(self, target or self.inst, weapon, multiplier, ...) if target and target:HasTag( "alwaysblock" ) then damageOriginal = 0x0 charBonus = 0x0 charBonusPercentage = 0x0 end elseif weaponComp and weaponComp.dycShouldOverrideCalcDamage then local multiplier = multiplier or 0x1 multiplier = multiplier * (self.GetDamageModifier and self:GetDamageModifier() or self.damagemultiplier or 0x1) local basedamage = self.defaultdamage or 0x0 local bonus = self.damagebonus or 0x0 if weapon then local weapondamage = 0x0 if weapon.components.weapon.variedmodefn then local d = weapon.components.weapon.variedmodefn(weapon) weapondamage = d.damage else weapondamage = weapon.components.weapon:GetDamage() end if not weapondamage then weapondamage = 0x0 end damageOriginal = weapondamage * multiplier + bonus else if self.inst.components.rider and self.inst.components.rider:IsRiding() then local mount = self.inst.components.rider:GetMount() if mount and mount.components.combat then basedamage = mount.components.combat.defaultdamage bonus = mount.components.combat.damagebonus or 0x0 end local saddle = self.inst.components.rider:GetSaddle() if saddle ~= nil and saddle.components.saddler ~= nil then basedamage = basedamage + saddle.components.saddler:GetBonusDamage() end end if target and target:HasTag( "player" ) then multiplier = self.playerdamagepercent * multiplier end damageOriginal = basedamage * multiplier + bonus end if target and target:HasTag( "alwaysblock" ) then damageOriginal = 0x0 charBonus = 0x0 charBonusPercentage = 0x0 end end local multiplier = multiplier or 0x1 multiplier = multiplier * (self.GetDamageModifier and self:GetDamageModifier() or self.damagemultiplier or 0x1) if target and target:HasTag( "player" ) then multiplier = self.playerdamagepercent * multiplier end local damage_base = damageOriginal local damage = math.max(damage_base + charBonus * multiplier, 0x0) * (0x1 + charBonusPercentage) local damage_bonus = damage - damage_base return damage, damage_base, damage_bonus end local function GetAttacked(self, attacker, damage, weapon, stimuli, ...) local inst = self.inst local health = inst and inst.components.health local hp = health and health.currenthealth local attackerCombat = attacker and attacker.components and attacker.components.combat local weaponInv = weapon and weapon.components and weapon.components.inventoryitem local weaponProj = weapon and weapon.components and weapon.components.projectile if not inst or not inst:IsValid() or (hp and hp <= 0x0) then return end if damage > 0x0 and attackerCombat then local inventory = attacker and attacker.components.inventory local equipslots = inventory and inventory.equipslots if equipslots then for k, v in pairs(equipslots) do if v.InvokeEventPreDamage then v:InvokeEventPreDamage(attacker, inst, weapon, damage) end end end if attacker.InvokeEventPreDamage then attacker:InvokeEventPreDamage(attacker, inst, weapon, damage) end if not self:GetWeapon() and weaponProj and weaponInv and not weaponInv.owner and weapon.InvokeEventPreDamage then weapon:InvokeEventPreDamage(attacker, inst, weapon, damage) end local inventory2 = inst and inst.components.inventory local equipslots2 = inventory2 and inventory2.equipslots if equipslots2 then for k, v in pairs(equipslots2) do if v.InvokeEventPreDamaged then v:InvokeEventPreDamaged(inst, attacker, weapon, damage) end end end if inst.InvokeEventPreDamaged then inst:InvokeEventPreDamaged(inst, attacker, weapon, damage) end end if inst.dycBlockNextDamage then damage = 0x0 inst.dycBlockNextDamage = nil end if damage > 0x0 then local charBonus, charBonusPercentage = GetReductionBonusData(self.inst) damage = math.max(0x0, damage * math.max(0x0, 0x1 - charBonusPercentage) - charBonus) end local retVal = self.dycOldGetAttacked(self, attacker, damage, weapon, stimuli, ...) local hpNew = health and health.currenthealth if hp and hpNew then hp = math.max(0x0, hp) hpNew = math.max(0x0, hpNew) local dmg = hp - hpNew if dmg > 0x0 and attackerCombat then local inventory = attacker and attacker.components.inventory local equipslots = inventory and inventory.equipslots if equipslots then for k, v in pairs(equipslots) do if v.InvokeEventDamage then v:InvokeEventDamage(attacker, inst, weapon, dmg) end end end if attacker.InvokeEventDamage then attacker:InvokeEventDamage(attacker, inst, weapon, dmg) end if not self:GetWeapon() and weaponProj and weaponInv and not weaponInv.owner and weapon.InvokeEventDamage then weapon:InvokeEventDamage(attacker, inst, weapon, dmg) end local inventory2 = inst and inst.components.inventory local equipslots2 = inventory2 and inventory2.equipslots if equipslots2 then for k, v in pairs(equipslots2) do if v.InvokeEventDamaged then v:InvokeEventDamaged(inst, attacker, weapon, dmg) end end end if inst.InvokeEventDamaged then inst:InvokeEventDamaged(inst, attacker, weapon, dmg) end end end return retVal end local function DoAttack(self, target_override, weapon, projectile, stimuli, instancemult, ...) local attacker = self.inst if attacker then attacker.dycIsManualEquipOrUnequip = true end local retVal = self.dycOldDoAttack(self, target_override, weapon, projectile, stimuli, instancemult, ...) if attacker then attacker.dycIsManualEquipOrUnequip = false end local target = target_override or self.target local weapon = weapon or self:GetWeapon() local canHitTarget = self:CanHitTarget(target, weapon) local weaponInv = weapon and weapon.components and weapon.components.inventoryitem local weaponProj = weapon and weapon.components and weapon.components.projectile if canHitTarget then local inventory = attacker and attacker.components.inventory local equipslots = inventory and inventory.equipslots if equipslots then for k, v in pairs(equipslots) do if v.InvokeEventAttack then v:InvokeEventAttack(attacker, target, weapon, projectile) end end end if attacker.InvokeEventAttack then attacker:InvokeEventAttack(attacker, target, weapon, projectile) end if not self:GetWeapon() and weaponProj and weaponInv and not weaponInv.owner and weapon.InvokeEventAttack then weapon:InvokeEventAttack(attacker, target, weapon, projectile) end local inventory2 = target and target.components.inventory local equipslots2 = inventory2 and inventory2.equipslots if equipslots2 then for k, v in pairs(equipslots2) do if v.InvokeEventAttacked then v:InvokeEventAttacked(target, attacker, weapon, projectile) end end end if target and target.InvokeEventAttacked then target:InvokeEventAttacked(target, attacker, weapon, projectile) end end return retVal end local function SetTarget(self, target, ...) local retVal = self.dycOldSetTarget(self, target, ...) if self.target then self.inst:InvokeEventTarget(self.inst, self.target) end return retVal end local function DYCCombat(self) self.dycOldCalcDamage = self.CalcDamage self.CalcDamage = CalcDamage self.dycOldGetAttacked = self.GetAttacked self.GetAttacked = GetAttacked self.dycOldDoAttack = self.DoAttack self.DoAttack = DoAttack self.dycOldSetTarget = self.SetTarget self.SetTarget = SetTarget self.CalcEstimatedDamage = CalcEstimatedDamage end return DYCCombat 